const content = $json.message.content;
console.log("Raw content:", content);
console.log("Finish reason:", $json.finish_reason);

let rawArticles = [];


// Normalize response by removing code block markers and isolating JSON
let cleanContent = content.trim();

// Remove code block markers (```json, ```), case-insensitive
cleanContent = cleanContent.replace(/```(?:json)?\s*/i, '').replace(/\s*```/g, '').trim();
console.log("Removed code block markers if present.");

// Try to extract just the array from surrounding content if needed
const arrayMatch = cleanContent.match(/\[\s*{[\s\S]*?}\s*]/);
if (arrayMatch) {
  cleanContent = arrayMatch[0];
  console.log("Extracted JSON array from mixed content.");
} else {
  console.log("No array match found — using full cleaned content.");
}


console.log("Clean content:", cleanContent);

// Check if response was truncated
if ($json.finish_reason === "length") {
  console.log("⚠️ Response was truncated due to length limit");

  // Try to salvage what we can
  try {
    // Find the last complete object
    const lastCompleteObjectEnd = cleanContent.lastIndexOf('}');
    if (lastCompleteObjectEnd !== -1) {
      // Find the array start
      const arrayStart = cleanContent.indexOf('[');
      if (arrayStart !== -1) {
        // Extract up to the last complete object and close the array
        let salvageContent = cleanContent.substring(arrayStart, lastCompleteObjectEnd + 1);

        // Check if we need to remove trailing comma
        if (salvageContent.trim().endsWith(',')) {
          salvageContent = salvageContent.trim().slice(0, -1);
        }

        salvageContent += '\n]';

        console.log("Attempting to parse salvaged content:", salvageContent.substring(0, 200) + "...");
        rawArticles = JSON.parse(salvageContent);
        console.log(`Successfully salvaged ${rawArticles.length} articles from truncated response`);
      }
    }
  } catch (salvageErr) {
    console.log("Failed to salvage truncated content:", salvageErr.message);
    throw new Error("Response was truncated and could not be salvaged. Try reducing input size.");
  }
} else {
  // Normal processing for complete responses
  try {
    rawArticles = JSON.parse(cleanContent);
    console.log(`Successfully parsed complete JSON with ${rawArticles.length} articles`);
  } catch (err) {
    console.log("Failed to parse complete JSON:", err.message);
    throw new Error("Failed to parse JSON: " + err.message);
  }
}

console.log("Articles before filtering:", rawArticles.length);

// Helper function to get property value case-insensitively
function getProperty(obj, propName) {
  // First try direct access
  if (obj[propName] !== undefined) return obj[propName];

  // Then try case-insensitive search
  const lowerProp = propName.toLowerCase();
  for (const key in obj) {
    if (key.toLowerCase() === lowerProp) {
      return obj[key];
    }
  }
  return undefined;
}

// FIXED: Filter out any placeholder/error articles using CASE-INSENSITIVE property names
rawArticles = rawArticles.filter(article => {
  const title = getProperty(article, 'title');
  const link = getProperty(article, 'link');

  console.log("Checking article:", article.id, title);
  return article.id && 
         title && 
         !title.includes("⚠️") &&
         link !== "#" &&
         link !== null;
});

console.log(`Final article count after filtering: ${rawArticles.length}`);

// Function to get emoji based on category
function getCategoryEmoji(category) {
  const emojiMap = {
    'Product Releases & Updates': '🚀',
    'AI Research & Breakthroughs': '🧠',  
    'Venture Capital & M&A': '💰',
    'Cybersecurity & Privacy': '🔒',
    'Drone Defence & Uncrewed Systems': '🚁',
    'Frontline Applications & Case Studies': '⚡',
    'Healthcare & Medical AI': '🏥',
    'Autonomous Vehicles': '🚗',
    'Tech Industry News': '📱',
    'Government & Policy': '🏛️',
    'Corporate Strategy & Partnerships': '🤝',
    'Ethics, Safety & Responsible AI': '⚖️',
    'Policy, Regulation & Governance': '📋'
  };
  return emojiMap[category] || '📰';
}

// Function to determine if article is "latest" (within last 2 days)
function isLatestArticle(dateString) {
  if (!dateString) return false;
  const articleDate = new Date(dateString);
  const twoDaysAgo = new Date();
  twoDaysAgo.setDate(twoDaysAgo.getDate() - 2);
  return articleDate > twoDaysAgo;
}

// Function to format date nicely
function formatDate(dateString) {
  if (!dateString) return 'Date not available';
  const date = new Date(dateString);
  return date.toLocaleDateString('en-US', { 
    year: 'numeric', 
    month: 'long', 
    day: 'numeric' 
  });
}

// Function to truncate content
function truncateContent(content, maxLength = 300) {
  if (!content || content.length <= maxLength) return content;
  return content.substring(0, maxLength) + '...';
}

// FIXED: Transform articles using CASE-INSENSITIVE property access
const transformedArticles = rawArticles.map(article => ({
  emoji: getCategoryEmoji(getProperty(article, 'category')),
  title: getProperty(article, 'title'),
  content: truncateContent(getProperty(article, 'summary')),
  source: `Source: ${getProperty(article, 'source')}`,
  isLatest: isLatestArticle(getProperty(article, 'date')),
  link: getProperty(article, 'link'),
  category: getProperty(article, 'category'),
  importance: getProperty(article, 'importance_score') || 0,
  virality: getProperty(article, 'virality_score') || 0,
  publishDate: formatDate(getProperty(article, 'date'))
}));

console.log(`Transformed ${transformedArticles.length} articles`);

// Sort by importance, then recency
transformedArticles.sort((a, b) => {
  if (b.importance !== a.importance) return b.importance - a.importance;
  return new Date(b.publishDate) - new Date(a.publishDate);
});

// Wrap for final HTML-ready data
const htmlData = {
  title: `Top AI & Tech News (Through ${formatDate(new Date())})`,
  subtitle: "🚀 AI Innovation | 🔒 Cybersecurity | 💰 Startup Funding | 🧠 Research Breakthroughs",
  siteName: "The AI Citizen",
  logoInitials: "AC",
  authorName: "The AI Citizen", 
  authorInitials: "AC",
  publishDate: formatDate(new Date()),
  introText: "Hello AI Citizens 🤖,",
  introBody: "From breakthrough AI research to major funding rounds, the tech landscape continues to evolve at breakneck speed. This week brings us exciting developments in autonomous systems, cybersecurity enhancements, and innovative applications across industries. Here's your comprehensive roundup of the most important AI and tech news shaping our digital future.",
  sectionTitle: "Here are the top stories:",
  articles: transformedArticles,
  totalArticles: transformedArticles.length,
  latestArticles: transformedArticles.filter(article => article.isLatest).length,
  categories: [...new Set(transformedArticles.map(article => article.category))],
  avgImportance: transformedArticles.length
    ? (transformedArticles.reduce((sum, article) => sum + article.importance, 0) / transformedArticles.length).toFixed(1)
    : "0.0"
};

console.log(`Final output: ${htmlData.totalArticles} articles, ${htmlData.categories.length} categories`);

return [{
  json: htmlData
}];

// Extract articles from the input data
const inputData = $input.first().json;
console.log("Input data received:", inputData.title);

// Get the articles array
const articles = inputData.articles || [];
console.log(`Found ${articles.length} articles to extract`);

if (articles.length === 0) {
  throw new Error("No articles found in the input data");
}

// Normalize keys inside each article
function normalizeKeys(obj) {
  const newObj = {};
  for (const key in obj) {
    if (Object.hasOwn(obj, key)) {
      newObj[key.toLowerCase()] = obj[key];  // Normalize all keys to lowercase
    }
  }
  return newObj;
}

// Filter out invalid articles
const validArticles = articles.filter((article) => {
  const normalized = normalizeKeys(article);
  const title = (normalized.title || '').toLowerCase();
  const link = (normalized.link || '').trim();

  // Exclude if title contains 'no' or 'not found' or link is empty
  return !(title.includes('no') && title.includes('found')) && link !== '';
});

console.log(`Filtered down to ${validArticles.length} valid articles`);

// Extract each article as a separate item
const extractedArticles = validArticles.map((article, index) => {
  const normalizedArticle = normalizeKeys(article);
  console.log(`Processing article ${index + 1}: ${normalizedArticle.title}`);

  return {
    json: {
      ...normalizedArticle,
      articleIndex: index + 1,
      totalArticles: validArticles.length,
      parentTitle: inputData.title,
      parentSiteName: inputData.siteName,
      parentPublishDate: inputData.publishDate
    }
  };
});

console.log(`Successfully extracted ${extractedArticles.length} articles`);

// Return each article as a separate item
return extractedArticles;

const raw = $json.message.content;

try {
  const parsed = JSON.parse(raw);

  // Extract first link from summarized content
  const linkMatch = parsed.Summarized_content.match(/\[.*?\]\((https?:\/\/.*?)\)/);
  const link = linkMatch ? linkMatch[1] : null;

  // Clean markdown, emojis, and remove "Source: [...]" block
  const cleanText = text => {
    return (text || '')
      .replace(/\n*\n*\*{0,2}Source:.*?\[.*?\]\(https?:\/\/.*?\)/gi, '')
      .replace(/\*\*/g, '')         // remove bold **
      .replace(/\*/g, '')           // remove italic *
      .replace(/[\u{1F300}-\u{1FAFF}]/gu, '') // remove emojis
      .trim();
  };

  return [
    {
      json: {
        Summarized_content: cleanText(parsed.Summarized_content),
        Insight: cleanText(parsed.insight),
        Link: link
      }
    }
  ];

} catch (err) {
  throw new Error("Failed to parse content as JSON: " + err.message);
}

const currentItems = $input.all();
const codeItem = $('Clean + Analyze Articles for HTML').first().json;
const codeArticles = codeItem.articles;

// Your debug logs...
console.log("currentItems length:", currentItems.length);
console.log("currentItems:", currentItems);
console.log("codeItem:", codeItem);
console.log("codeArticles:", codeArticles);
console.log("codeArticles length:", codeArticles?.length);

// Normalize URLs
const normalizeUrl = url => {
  return (url || '')
    .trim()
    .replace(/\/+$/, '');
};

// Clean formatting
const cleanText = text => {
  return (text || '')
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/[\u{1F300}-\u{1FAFF}]/gu, '')
    .trim();
};

// Build merged articles
const mergedArticles = codeArticles.reduce((acc, article) => {
  console.log(acc, "====acc==")
  const articleLink = normalizeUrl(article.link);
  console.log("Looking for article link:", articleLink);

  const matchedItem = currentItems.find(item => {
    const itemLink = normalizeUrl(item.json?.fields?.Link);
    console.log(itemLink, "===item link==")
    console.log("Comparing:", itemLink, "vs", articleLink);
    return itemLink === articleLink;
  });

  if (matchedItem) {
    acc.push({
      ...article, // Spread all original article properties
      Summarized_contetnt: cleanText(matchedItem.json?.fields?.Summarized_contetnt),
      Insight: cleanText(matchedItem.json?.fields?.Insight)
    });
  }
  return acc;
}, []);

console.log(mergedArticles, "====merged articles===+++");

return [
  {
    json: {
      articles: mergedArticles
    }
  }
];

const input = $input.item.json;
const articles = input.articles || [];

return articles.map(article => ({
  json: {
    ...article,
    context: {
      title: article.title,
      link: article.link
    }
  }
}));

const allResponses = await $input.all();
const allVideos = [];

for (let i = 0; i < allResponses.length; i++) {
  const response = allResponses[i];
  const youtubeResponse = response.json;
  const context = response.json?.context || {}; // safe fallback

  if (!youtubeResponse.items || youtubeResponse.items.length === 0) {
    continue; // Skip if no videos found
  }

  const videos = youtubeResponse.items.map((item) => {
    const videoId = item.id?.videoId;
    const snippet = item.snippet;

    return {
      index: i,  // Use original response index here
      videoId,
      title: snippet?.title?.replace(/&#39;/g, "'").replace(/&quot;/g, '"') || 'No title',
      description: snippet?.description ? snippet.description.substring(0, 150) + '...' : 'No description',
      channelTitle: snippet?.channelTitle || '',
      publishedAt: snippet?.publishedAt || '',
      thumbnail: snippet?.thumbnails?.high?.url || snippet?.thumbnails?.medium?.url || '',
      url: `https://www.youtube.com/watch?v=${videoId}`,
      embedUrl: `https://www.youtube.com/embed/${videoId}`,
      shareUrl: `https://youtu.be/${videoId}`,
      articleTitle: context.title || '',
      articleLink: context.link || ''
    };
  });

  allVideos.push(...videos);
}

// Optional deduplication based on videoId
const uniqueVideos = [];
const seen = new Set();

for (const video of allVideos) {
  if (!seen.has(video.videoId)) {
    seen.add(video.videoId);
    uniqueVideos.push(video);
  }
}

return uniqueVideos.map(video => ({ json: video }));

const data = $(' Merge Articles + Add Insights').first().json;
const youtube_data = $("Process YouTube Results").first().json;

console.log(data, '=== merged article data ===');
console.log(youtube_data, "=== youtube data ===");

let combine_output = [...data.articles];

// Normalize to array
const youtubeArray = Array.isArray(youtube_data) ? youtube_data : [youtube_data];

// Loop through YouTube data and enrich articles
youtubeArray.forEach(video => {
  const idx = video.index;
  if (combine_output[idx]) {
    combine_output[idx].youtubeThumbnail = video.thumbnail;
    combine_output[idx].youtubeUrl = video.url;
    combine_output[idx].youtubeEmbedUrl = video.embedUrl;
    combine_output[idx].youtubeTitle = video.title;
  }
});

console.log(combine_output, '=== combined output ===');


return combine_output

